"use client";
import React from "react";
import "@copilotkit/react-ui/styles.css";
import "./style.css";
import { CopilotKit, useCoAgentStateRender } from "@copilotkit/react-core";
import { CopilotChat } from "@copilotkit/react-ui";
import { CustomAssistantMessage } from "@/components/ui/custom-assistant-message";

const AgenticGenerativeUI: React.FC = () => {
  return (
    <CopilotKit
      runtimeUrl="/api/copilotkit"
      showDevConsole={false}
      // agent lock to the relevant agent
      agent="agentic_generative_ui"
    >
      <Chat />
    </CopilotKit>
  );
};

interface AgentState {
  steps: {
    description: string;
    status: "pending" | "completed";
  }[];
}

const Chat = () => {
  useCoAgentStateRender<AgentState>({
    name: "agentiveGenerativeUIAgent",
    render: ({ state }) => {
      if (!state.steps || state.steps.length === 0) {
        return null;
      }

      return (
        <div className="flex">
          <div className="bg-gray-100 rounded-lg w-[500px] p-4 text-black space-y-2">
            {state.steps.map((step, index) => {
              if (step.status === "completed") {
                return (
                  <div key={index} className="text-sm">
                    ✓ {step.description}
                  </div>
                );
              } else if (
                step.status === "pending" &&
                index === state.steps.findIndex((s) => s.status === "pending")
              ) {
                return (
                  <div
                    key={index}
                    className="text-3xl font-bold text-slate-700"
                  >
                    <Spinner />
                    {step.description}
                  </div>
                );
              } else {
                return (
                  <div key={index} className="text-sm">
                    <Spinner />
                    {step.description}
                  </div>
                );
              }
            })}
          </div>
        </div>
      );
    },
  });

  return (
    <div className="flex justify-center items-center h-full w-full">
      <div className="w-8/10 h-8/10 rounded-lg">
        <CopilotChat
          className="h-full rounded-2xl"
          labels={{
            initial:
              "Hi, I'm an agent! I can help you with anything you need and will show you progress as I work. What can I do for you?",
          }}
          AssistantMessage={CustomAssistantMessage}
        />
      </div>
    </div>
  );
};

function Spinner() {
  return (
    <svg
      className="mr-2 size-3 animate-spin text-slate-500"
      xmlns="http://www.w3.org/2000/svg"
      fill="none"
      viewBox="0 0 24 24"
    >
      <circle
        className="opacity-25"
        cx="12"
        cy="12"
        r="10"
        stroke="currentColor"
        strokeWidth="4"
      ></circle>
      <path
        className="opacity-75"
        fill="currentColor"
        d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
      ></path>
    </svg>
  );
}

export default AgenticGenerativeUI;

.copilotKitInput {
  border-bottom-left-radius: 0.75rem;
  border-bottom-right-radius: 0.75rem;
  border-top-left-radius: 0.75rem;
  border-top-right-radius: 0.75rem;
  border: 1px solid var(--copilot-kit-separator-color) !important;
}

.copilotKitChat {
  background-color: #fff !important;
}

#!/usr/bin/env python
"""
An example demonstrating agentic generative UI.
"""

from dotenv import load_dotenv
load_dotenv(override=True)
import logging
from typing import Optional
from crewai import LLM
from crewai.flow import start, persist
import sys
from pydantic import BaseModel, Field
from typing import List, Dict, Any

from copilotkit.crewai import (
    CopilotKitFlow,
    FlowInputState,
)

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

llm = LLM(model="gpt-4o", stream=False)

GENERATE_TASK_STEPS_TOOL = {
    "type": "function",
    "function": {
        "name": "generate_task_steps",
        "description": "Generate a list of steps required to complete a task",
        "parameters": {
            "type": "object",
            "properties": {
                "task": {
                    "type": "string",
                    "description": "The task to generate steps for"
                },
                "steps": {
                    "type": "array",
                    "items": {
                        "type": "object",
                        "properties": {
                            "step_number": {"type": "integer"},
                            "description": {"type": "string"},
                            "enabled": {"type": "boolean", "default": True}
                        },
                        "required": ["step_number", "description"]
                    },
                    "description": "Array of steps needed to complete the task"
                }
            },
            "required": ["task", "steps"]
        }
    }
}

class TaskSteps(BaseModel):
    """
    Task steps with user-controllable enable/disable functionality.
    """
    task: str = Field(..., description="The task description")
    steps: List[Dict[str, Any]] = Field(..., description="List of task steps")

class AgentState(FlowInputState):
    """
    The state of the task execution.
    """
    task_steps: Optional[dict] = None

@persist()
class HumanInTheLoopFlow(CopilotKitFlow[AgentState]):

    @start()
    def chat(self):
        """
        Standard chat node that processes messages and handles tool calls.
        """

        system_prompt = """
        You are a helpful assistant that can perform any task.

        • If the **latest user message** is a fresh task request, CALL `generate_task_steps` to break it down, then stop.
        • If the message shows the user already enabled/disabled steps, DO NOT call anything—reply in ≤3 funny sentences about how you're doing the task (invent clever work-arounds for any disabled bits).
        • Otherwise, ask a clarifying question.

        You only see the most recent user message—derive everything from that.
        """
        # Get message history using the base class method
        messages = self.get_message_history(system_prompt=system_prompt)

        print(f"Messages: {messages}")

        return llm.call(
            messages=messages,
            tools=[GENERATE_TASK_STEPS_TOOL],
            available_functions={"generate_task_steps": self.generate_task_steps_handler}
        )

    def generate_task_steps_handler(self, task, steps):
        """Handler for the generate_task_steps tool"""
        # Ensure all steps have the 'enabled' field set to True by default
        for step in steps:
            if 'enabled' not in step:
                step['enabled'] = True
                logger.info(f"Added enabled=True to step {step.get('step_number', '?')}: {step.get('description', 'Unknown')[:50]}...")

        task_steps_obj = TaskSteps(
            task=task,
            steps=steps
        )

        return task_steps_obj.model_dump_json(indent=2)


def kickoff():
    """
    Start the flow with comprehensive logging and event bus diagnostics
    """
    result = HumanInTheLoopFlow().kickoff({
        "messages": [
            {
                "role": "user",
                "content": "go to mars!"
            }
        ]
    })
    print(f"result: {result}")

if __name__ == "__main__":
    sys.exit(kickoff())

"use client";
import React, { useState, useEffect } from "react";
import "@copilotkit/react-ui/styles.css";
import "./style.css";
import { CopilotKit, useCopilotAction } from "@copilotkit/react-core";
import { CopilotChat } from "@copilotkit/react-ui";
import { initialPrompt } from "@/lib/prompts";

const HumanInTheLoop: React.FC = () => {
  return (
    <CopilotKit
      runtimeUrl="/api/copilotkit"
      showDevConsole={false}
      agent="human_in_the_loop"
    >
      <Chat />
    </CopilotKit>
  );
};

const Chat = () => {
  useCopilotAction({
    name: "generate_task_steps",
    parameters: [
      {
        name: "steps",
        type: "object[]",
        attributes: [
          {
            name: "description",
            type: "string",
          },
          {
            name: "enabled",
            type: "string",
          },
          {
            name: "step_number",
            type: "string",
          },
        ],
      },
    ],
    renderAndWaitForResponse: ({ args, respond, status }) => {
      console.log("args", args);
      const modifiedArgs = {
        ...args,
        steps: args?.steps?.map((step) => ({
          ...step,
          enabled: step.enabled === "True",
        })),
      };

      return (
        <StepsFeedback args={modifiedArgs} respond={respond} status={status} />
      );
    },
  });

  return (
    <div className="flex justify-center items-center h-full w-full">
      <div className="w-8/10 h-8/10 rounded-lg">
        <CopilotChat
          className="h-full rounded-2xl"
          labels={{ initial: initialPrompt.humanInTheLoop }}
        />
      </div>
    </div>
  );
};

const StepsFeedback = ({
  args,
  respond,
  status,
}: {
  args: any;
  respond: any;
  status: any;
}) => {
  const [localSteps, setLocalSteps] = useState<
    {
      description: string;
      enabled: boolean;
      step_number: number;
    }[]
  >([]);
  const [newStep, setNewStep] = useState("");

  console.log("args.steps", args.steps);

  useEffect(() => {
    if (status === "executing" && localSteps.length === 0) {
      setLocalSteps(args.steps);
    }
  }, [status, args.steps, localSteps]);

  if (args.steps === undefined || args.steps.length === 0) {
    return <></>;
  }

  const steps = localSteps.length > 0 ? localSteps : args.steps;

  const handleCheckboxChange = (index: number) => {
    console.log("handleCheckboxChange", index);
    setLocalSteps((prevSteps) =>
      prevSteps.map((step, i) =>
        i === index
          ? {
              ...step,
              enabled: !step.enabled,
            }
          : step
      )
    );
  };

  const handleAddStep = () => {
    const trimmed = newStep.trim();
    if (trimmed.length === 0) return;
    setLocalSteps((prevSteps) => [
      ...prevSteps,
      { description: trimmed, enabled: true, step_number: 0 },
    ]);
    setNewStep("");
  };

  const handleInputKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter") {
      handleAddStep();
    }
  };

  return (
    <div className="flex flex-col gap-4 w-[500px] bg-gray-100 rounded-lg p-8 mb-4">
      <div className=" text-black space-y-2">
        <h2 className="text-lg font-bold mb-4">Select Steps</h2>
        {steps.map((step: any, index: any) => (
          <div key={index} className="text-sm flex items-center">
            <label className="flex items-center cursor-pointer">
              <input
                type="checkbox"
                checked={step.enabled}
                onChange={() => {
                  if (respond) {
                    handleCheckboxChange(index);
                  }
                }}
                className="mr-2"
              />
              <span
                className={
                  !step.enabled && status != "inProgress" ? "line-through" : ""
                }
              >
                {step.description}
              </span>
            </label>
          </div>
        ))}
        <div className="flex items-center gap-2 mb-4">
          <input
            type="text"
            className="flex-1 rounded py-2 focus:outline-none"
            placeholder="Add a new step..."
            value={newStep}
            onChange={(e) => setNewStep(e.target.value)}
            onKeyDown={handleInputKeyDown}
            hidden={status != "executing"}
          />
        </div>
        {status === "executing" && (
          <button
            className="mt-4 bg-gradient-to-r from-purple-400 to-purple-600 text-white py-2 px-4 rounded cursor-pointer w-48 font-bold"
            onClick={() => {
              const selectedSteps = localSteps
                .filter((step) => step.enabled)
                .map((step) => step.description);
              respond(
                "The user selected the following steps: " +
                  selectedSteps.join(", ")
              );
            }}
          >
            ✨ Perform Steps
          </button>
        )}
      </div>
    </div>
  );
};

export default HumanInTheLoop;

